import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const dirs = [[0, 1], [1, 0], [-1, 0], [0, -1]];
    const dist = Array.from({ length: m }, () => 
        Array.from({ length: n }, () => 
            Array(k + 1).fill(Infinity)
        )
    );
    dist[0][0][0] = 0;

    const pq = new MinPriorityQueue({ priority: (a) => a[0] });
    pq.enqueue([0, 0, 0, 0]);

    while (!pq.isEmpty()) {
        const [currentCost, i, j, usedK] = pq.dequeue().element;
        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }
        if (currentCost > dist[i][j][usedK]) {
            continue;
        }

        // Normal moves
        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = currentCost + grid[ni][nj];
                if (newCost < dist[ni][nj][usedK]) {
                    dist[ni][nj][usedK] = newCost;
                    pq.enqueue([newCost, ni, nj, usedK]);
                }
            }
        }

        // Teleport moves
        if (usedK < k) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j] && (x !== i || y !== j)) {
                        if (currentCost < dist[x][y][usedK + 1]) {
                            dist[x][y][usedK + 1] = currentCost;
                            pq.enqueue([currentCost, x, y, usedK + 1]);
                        }
                    }
                }
            }
        }
    }

    return Math.min(...dist[m - 1][n - 1]);
}

