#include <vector>
#include <queue>
#include <climits>
#include <tuple>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    // Directions: right, down, left, up
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};

    // dist[i][j][l] = minimal cost to reach (i,j) with l teleports used
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, LLONG_MAX)));
    dist[0][0][0] = 0;

    // Priority queue: (cost, i, j, usedK)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<tuple<long long, int, int, int>>> pq;
    pq.push({0, 0, 0, 0});

    while (!pq.empty()) {
        auto [currentCost, i, j, usedK] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return currentCost;
        }

        if (currentCost > dist[i][j][usedK]) {
            continue;
        }

        // Normal moves
        for (auto [di, dj] : dirs) {
            int ni = i + di;
            int nj = j + dj;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long newCost = currentCost + grid[ni][nj];
                if (newCost < dist[ni][nj][usedK]) {
                    dist[ni][nj][usedK] = newCost;
                    pq.push({newCost, ni, nj, usedK});
                }
            }
        }

        // Teleport moves
        if (usedK < k) {
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j] && (x != i || y != j)) {
                        if (currentCost < dist[x][y][usedK + 1]) {
                            dist[x][y][usedK + 1] = currentCost;
                            pq.push({currentCost, x, y, usedK + 1});
                        }
                    }
                }
            }
        }
    }

    long long result = LLONG_MAX;
    for (int l = 0; l <= k; l++) {
        if (dist[m-1][n-1][l] < result) {
            result = dist[m-1][n-1][l];
        }
    }
    return result;
}
